import { MapContainer, TileLayer, Marker, Polyline } from "react-leaflet"
import { useEffect, useState } from "react"
import L from "leaflet"
import "leaflet/dist/leaflet.css"

// 🔥 IMPORTANT FIX FOR MARKER ICONS
delete L.Icon.Default.prototype._getIconUrl
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon-2x.png",
  iconUrl: "https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon.png",
  shadowUrl: "https://unpkg.com/leaflet@1.7.1/dist/images/marker-shadow.png",
})

export default function MapPage() {

  const [bins, setBins] = useState([])
  const [route, setRoute] = useState([])

  // 🔥 LOAD DATA FROM BACKEND
  useEffect(() => {
    fetch("http://127.0.0.1:5000/bins")
      .then(res => res.json())
      .then(data => setBins(data))

    fetch("http://127.0.0.1:5000/route")
      .then(res => res.json())
      .then(data => setRoute(data))
  }, [])

  // 🔥 CONVERT ROUTE
  const routeCoords = route.map(r => [r.Latitude, r.Longitude])

  return (
    <div>
      <h2>🔥 Smart Waste Heatmap + Route</h2>

      <MapContainer
        center={[12.97, 77.59]}
        zoom={11}
        style={{ height: "500px", width: "100%" }}
      >

        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        {/* 🔥 HEATMAP USING CIRCLE (WORKS 100%) */}
        {bins.map(bin => (
          <CircleMarker
            key={bin.Bin_ID}
            center={[bin.Latitude, bin.Longitude]}
            radius={20}
            pathOptions={{
              color:
                bin.Waste_Level > 80 ? "red" :
                bin.Waste_Level > 50 ? "yellow" :
                "green",
              fillOpacity: 0.5
            }}
          />
        ))}

        {/* 🔵 MARKERS */}
        {bins.map(bin => (
          <Marker
            key={bin.Bin_ID + "_marker"}
            position={[bin.Latitude, bin.Longitude]}
          />
        ))}

        {/* 🚛 ROUTE */}
        <Polyline positions={routeCoords} color="blue" />

      </MapContainer>
    </div>
  )
}
